#include<bits/stdc++.h>
using namespace std;

#define ll long long

ll n,t,v[10000001],w[10001000],dp[10000001];

int main(){
	cin>>t;
    for(int i=1;i<=t;i++)
        dp[i]=1e8;
     int n=ceil(sqrt(sqrt(t))+1);
	 for(int i=1;i<=n;i++)
        for(int j=i*i*i*i;j<=t;j++)
            dp[j]=min(dp[j],dp[j-i*i*i*i]+1);
    cout<<dp[t];
	return 0;
}
